import React, { useEffect, useState } from 'react';
import { adminLogin, adminLogout, adminCreateTournament, fetchTournaments, getAdminToken } from '../utils/typingApi';
import '../styles/AdminPanel.css';

const ADMIN_EMAIL = 'caleb@gmail.com';

export default function AdminPanel() {
  const [token, setToken] = useState(getAdminToken());
  const [loginData, setLoginData] = useState({ email: '', password: '' });
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    entryFee: '',
    prizePool: '',
    maxParticipants: '',
    status: 'upcoming',
    duration: '60s',
    image: '??',
    startTime: '',
  });
  const [notice, setNotice] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [tournaments, setTournaments] = useState([]);

  const loadTournaments = async () => {
    const data = await fetchTournaments();
    setTournaments(data);
  };

  useEffect(() => {
    if (token) {
      loadTournaments();
    }
  }, [token]);

  const handleAdminLogin = async (e) => {
    e.preventDefault();
    try {
      const result = await adminLogin(loginData.email, loginData.password);
      setToken(result.token);
      setNotice('Admin login successful.');
      setLoginData({ email: '', password: '' });
    } catch (error) {
      setNotice(error.message || 'Admin login failed.');
    }
  };

  const handleCreateTournament = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      const payload = {
        ...formData,
        entryFee: Number(formData.entryFee),
        prizePool: Number(formData.prizePool),
        maxParticipants: Number(formData.maxParticipants),
        startTime: formData.startTime || undefined,
      };
      const result = await adminCreateTournament(payload);
      setNotice(result.message || 'Tournament created successfully.');
      setFormData({
        name: '',
        description: '',
        entryFee: '',
        prizePool: '',
        maxParticipants: '',
        status: 'upcoming',
        duration: '60s',
        image: '??',
        startTime: '',
      });
      await loadTournaments();
    } catch (error) {
      setNotice(error.message || 'Could not create tournament.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleSignOut = () => {
    adminLogout();
    setToken(null);
    setNotice('Admin signed out.');
  };

  return (
    <div className="admin-container">
      <div className="admin-header">
        <h1>Admin Panel</h1>
        <p>Create and manage tournaments</p>
      </div>

      {notice && <div className="admin-notice">{notice}</div>}

      {!token ? (
        <form className="admin-card admin-form" onSubmit={handleAdminLogin}>
          <h2>Admin Login</h2>
          <p>Use email: <strong>{ADMIN_EMAIL}</strong></p>
          <input
            type="email"
            placeholder="Admin Email"
            value={loginData.email}
            onChange={(e) => setLoginData((prev) => ({ ...prev, email: e.target.value }))}
            required
          />
          <input
            type="password"
            placeholder="Password"
            value={loginData.password}
            onChange={(e) => setLoginData((prev) => ({ ...prev, password: e.target.value }))}
            required
          />
          <button type="submit" className="btn btn-primary">Login as Admin</button>
        </form>
      ) : (
        <>
          <div className="admin-actions">
            <button className="btn btn-outline-primary" onClick={handleSignOut}>Sign Out Admin</button>
          </div>

          <form className="admin-card admin-form" onSubmit={handleCreateTournament}>
            <h2>Create Tournament</h2>
            <input
              type="text"
              placeholder="Tournament Name"
              value={formData.name}
              onChange={(e) => setFormData((prev) => ({ ...prev, name: e.target.value }))}
              required
            />
            <textarea
              placeholder="Description"
              value={formData.description}
              onChange={(e) => setFormData((prev) => ({ ...prev, description: e.target.value }))}
              rows={3}
            />

            <div className="admin-grid">
              <input
                type="number"
                min="0"
                placeholder="Entry Fee"
                value={formData.entryFee}
                onChange={(e) => setFormData((prev) => ({ ...prev, entryFee: e.target.value }))}
                required
              />
              <input
                type="number"
                min="0"
                placeholder="Prize Pool"
                value={formData.prizePool}
                onChange={(e) => setFormData((prev) => ({ ...prev, prizePool: e.target.value }))}
                required
              />
              <input
                type="number"
                min="1"
                placeholder="Max Participants"
                value={formData.maxParticipants}
                onChange={(e) => setFormData((prev) => ({ ...prev, maxParticipants: e.target.value }))}
                required
              />
              <input
                type="text"
                placeholder="Duration e.g. 60s"
                value={formData.duration}
                onChange={(e) => setFormData((prev) => ({ ...prev, duration: e.target.value }))}
                required
              />
              <input
                type="text"
                placeholder="Emoji/Icon"
                value={formData.image}
                onChange={(e) => setFormData((prev) => ({ ...prev, image: e.target.value }))}
              />
              <select
                value={formData.status}
                onChange={(e) => setFormData((prev) => ({ ...prev, status: e.target.value }))}
              >
                <option value="upcoming">Upcoming</option>
                <option value="active">Active</option>
                <option value="completed">Completed</option>
              </select>
            </div>

            <input
              type="datetime-local"
              value={formData.startTime}
              onChange={(e) => setFormData((prev) => ({ ...prev, startTime: e.target.value }))}
            />

            <button type="submit" className="btn btn-primary" disabled={isSubmitting}>
              {isSubmitting ? 'Creating...' : 'Create Tournament'}
            </button>
          </form>

          <div className="admin-card">
            <h2>Existing Tournaments</h2>
            <div className="admin-list">
              {tournaments.map((t) => (
                <div key={t.id} className="admin-list-item">
                  <strong>{t.name}</strong>
                  <span>KES {Number(t.entryFee).toLocaleString()} | {t.participants}/{t.maxParticipants} | {t.status}</span>
                </div>
              ))}
            </div>
          </div>
        </>
      )}
    </div>
  );
}
